def build_inputs(torch, device, dtype):
    left = torch.randn((128, 512), device=device, dtype=dtype)
    right = torch.randn((512, 1536), device=device, dtype=dtype)
    return left, right

def run_kernel(torch, left, right):
    return torch.matmul(left, right)

def build_inputs(torch, device, dtype):
    scores = torch.randn((1024, 128), device=device, dtype=dtype)
    return (scores,)

def run_kernel(torch, scores):
    return torch.softmax(scores, dim=-1)

def build_inputs(torch, device, dtype):
    left = torch.randn((128, 2048), device=device, dtype=dtype)
    right = torch.randn((2048, 512), device=device, dtype=dtype)
    return left, right

def run_kernel(torch, left, right):
    return torch.matmul(left, right)
